#### **`authorize()`**
**Propósito**: Autorização baseada em políticas dinâmicas  
**Lógica**:
```typescript
export const authorize = () => {
  return async (req: Request, res: Response, next: NextFunction) => {
    if (!req.session.user) {
      // Log de tentativa não autorizada
      await storage.createAuditLog({
        userId: req.session.userId || "anonymous",
        action: "unauthorized_access",
        entityType: "route",
        entityId: req.path,
        details: { method: req.method, path: req.path },
        ipAddress: req.ip,
      });
      return res.status(401).json({ message: "Unauthorized" });
    }

    // Busca política para a rota
    const allowedRoles = matchPolicy(req.method, req.path);

    if (!allowedRoles) {
      return res.status(404).json({ message: "Not found" });
    }

    // Rota pública
    if (allowedRoles[0] === "*") {
      return next();
    }

    // Verifica se role do usuário está permitido
    if (!allowedRoles.includes(req.session.user.role)) {
      await storage.createAuditLog({
        userId: req.session.user.id,
        action: "forbidden_access",
        entityType: "route",
        entityId: req.path,
        details: { 
          method: req.method, 
          path: req.path,
          required: allowedRoles,
          current: req.session.user.role 
        },
        ipAddress: req.ip,
      });

      return res.status(403).json({ 
        message: "Forbidden: Insufficient permissions",
        required: allowedRoles,
        current: req.session.user.role
      });
    }

    next();
  };
};
```

