                <div className="text-center py-8 text-muted-foreground">
                  <Truck className="h-12 w-12 mx-auto mb-3 opacity-30" />
                  <p className="text-sm">{t('dashboard.noSharesYet')}</p>
                  <p className="text-xs mt-1">{t('dashboard.startInvesting')}</p>
                </div>
              )}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

