        investor: string;
        shares: number;
        amount: number;
      }>;
    }
  ): Buffer {
    const doc = new jsPDF();

    this.addHeader(doc, 'Monthly Financial Report');

    let yPos = 50;

    doc.setFontSize(18);
    doc.setFont('helvetica', 'bold');
