        p.investor,
        p.shares.toString(),
        this.formatCurrency(p.amount)
      ]),
      theme: 'striped',
      headStyles: { 
        fillColor: [33, 51, 82],
        textColor: [255, 255, 255],
        fontStyle: 'bold'
      },
      styles: { fontSize: 9 },
      columnStyles: {
        1: { halign: 'center' },
        2: { halign: 'right', fontStyle: 'bold' }
      }
    });

    this.addFooter(doc);

