import bcrypt from "bcrypt";
import { db } from "../server/db";
import { users } from "../shared/schema";
import { eq } from "drizzle-orm";

const DEV_PASSWORDS = {
  "investor@example.com": "investor123",
  "manager@example.com": "manager123",
  "investor2@example.com": "investor123"
};

async function resetDevPasswords() {
  console.log("🔐 Resetting development user passwords...\n");

  for (const [email, password] of Object.entries(DEV_PASSWORDS)) {
    try {
      const hashedPassword = await bcrypt.hash(password, 10);

      const result = await db
        .update(users)
        .set({ password: hashedPassword })
        .where(eq(users.email, email))
        .returning();

      if (result.length > 0) {
        console.log(`✅ Reset password for: ${email}`);
        console.log(`   Username: ${result[0].username}`);
        console.log(`   Role: ${result[0].role}`);
        console.log(`   Password: ${password}\n`);
      } else {
        console.log(`⚠️  User not found: ${email}\n`);
      }
    } catch (error) {
      console.error(`❌ Error resetting password for ${email}:`, error);
    }
  }

  console.log("\n📋 Development Login Credentials:");
  console.log("═══════════════════════════════════════════════════════");
  console.log("\n👨‍💼 Manager Account:");
  console.log("   Email:    manager@example.com");
  console.log("   Password: manager123");
  console.log("   Role:     manager (full access)");

  console.log("\n💰 Investor Account 1:");
  console.log("   Email:    investor@example.com");
  console.log("   Password: investor123");
  console.log("   Role:     investor (portfolio view only)");

  console.log("\n💰 Investor Account 2:");
  console.log("   Email:    investor2@example.com");
  console.log("   Password: investor123");
  console.log("   Role:     investor (portfolio view only)");

  console.log("\n═══════════════════════════════════════════════════════");
  console.log("⚠️  These are DEVELOPMENT credentials only!");
  console.log("   Never use these passwords in production.\n");

  process.exit(0);
}

resetDevPasswords().catch((error) => {
  console.error("Fatal error:", error);
  process.exit(1);
});

server/websocket.ts.content:
import WebSocket, { WebSocketServer } from 'ws';
import { IncomingMessage } from 'http';
import type { Server } from 'http';

interface ExtendedWebSocket extends WebSocket {
  userId?: string;
  isAlive?: boolean;
}

export class NotificationWebSocketServer {
  private wss: WebSocketServer;
  private clients: Map<string, Set<ExtendedWebSocket>> = new Map();

  constructor(server: Server) {
    this.wss = new WebSocketServer({ server, path: '/ws/notifications' });

    this.wss.on('connection', this.handleConnection.bind(this));
    this.startHeartbeat();

    console.log('[WebSocket] Notification server initialized on /ws/notifications');
  }

  private handleConnection(ws: ExtendedWebSocket, req: IncomingMessage) {
    ws.isAlive = true;

    ws.on('pong', () => {
      ws.isAlive = true;
    });

    ws.on('message', (data: string) => {
      try {
        const message = JSON.parse(data.toString());

        if (message.type === 'auth' && message.userId) {
          this.registerClient(message.userId, ws);
          ws.send(JSON.stringify({ 
            type: 'auth_success', 
            message: 'WebSocket connected successfully',
            timestamp: new Date().toISOString()
          }));
        }
      } catch (error) {
        console.error('[WebSocket] Error handling message:', error);
      }
    });

    ws.on('close', () => {
      this.unregisterClient(ws);
    });

    ws.on('error', (error) => {
      console.error('[WebSocket] Connection error:', error);
      this.unregisterClient(ws);
    });
  }

  private registerClient(userId: string, ws: ExtendedWebSocket) {
    ws.userId = userId;

    if (!this.clients.has(userId)) {
      this.clients.set(userId, new Set());
    }

    this.clients.get(userId)!.add(ws);
    console.log(`[WebSocket] Client registered: userId=${userId}, total clients=${this.clients.get(userId)!.size}`);
  }

  private unregisterClient(ws: ExtendedWebSocket) {
    if (ws.userId) {
      const userClients = this.clients.get(ws.userId);
      if (userClients) {
        userClients.delete(ws);
        if (userClients.size === 0) {
          this.clients.delete(ws.userId);
        }
        console.log(`[WebSocket] Client unregistered: userId=${ws.userId}`);
      }
    }
  }

  private startHeartbeat() {
    setInterval(() => {
      this.wss.clients.forEach((ws: WebSocket) => {
        const extWs = ws as ExtendedWebSocket;

        if (extWs.isAlive === false) {
          this.unregisterClient(extWs);
          return extWs.terminate();
        }

        extWs.isAlive = false;
        extWs.ping();
      });
    }, 30000);
  }

  public sendToUser(userId: string, notification: any) {
    const userClients = this.clients.get(userId);

    if (!userClients || userClients.size === 0) {
      console.log(`[WebSocket] No active connections for user: ${userId}`);
      return false;
    }

    let sent = 0;
    userClients.forEach((ws) => {
      if (ws.readyState === WebSocket.OPEN) {
        ws.send(JSON.stringify({
          type: 'notification',
          data: notification,
          timestamp: new Date().toISOString()
        }));
        sent++;
      }
    });

    console.log(`[WebSocket] Sent notification to ${sent} client(s) for user: ${userId}`);
    return sent > 0;
  }

  public broadcast(notification: any, userIds?: string[]) {
    const targetUsers = userIds || Array.from(this.clients.keys());

    let totalSent = 0;
    targetUsers.forEach((userId) => {
      if (this.sendToUser(userId, notification)) {
        totalSent++;
      }
    });

    return totalSent;
  }

  public getConnectedUsers(): string[] {
    return Array.from(this.clients.keys());
  }

  public getConnectionCount(userId?: string): number {
    if (userId) {
      return this.clients.get(userId)?.size || 0;
    }
    return Array.from(this.clients.values()).reduce((sum, set) => sum + set.size, 0);
  }
}

let wsServer: NotificationWebSocketServer | null = null;

export function initializeWebSocket(server: Server): NotificationWebSocketServer {
  if (!wsServer) {
    wsServer = new NotificationWebSocketServer(server);
  }
  return wsServer;
}

export function getWebSocketServer(): NotificationWebSocketServer {
  if (!wsServer) {
    throw new Error('WebSocket server not initialized');
  }
  return wsServer;
}

